"import json\nimport os\n\nlog_path = r\"C:\\Users\\GIRTEC\\.gemini\\antigravity-cli\\brain\\a8e23cc2-b402-44c7-a956-a3b161a20562\\.system_generated\\logs\\transcript.jsonl\"\nlog_full_path = r\"C:\\Users\\GIRTEC\\.gemini\\antigravity-cli\\brain\\a8e23cc2-b402-44c7-a956-a3b161a20562\\.system_generated\\logs\\transcript_full.jsonl\"\n\ndef search_log(path):\n    if not os.path.exists(path):\n        return None\n    with open(path, 'r', encoding='utf-8', errors='ignore') as f:\n        for line in f:\n            if 'build_pcb.py' in line:\n                try:\n                    obj = json.loads(line)\n                    # Let's search inside the fields\n                    content = str(obj)\n                    if 'import pcbnew' in content or 'pcbnew.GetBoard' in content:\n                        return obj\n                except Exception as e:\n                    pass\n    return None\n\nprint(\"Checking transcript.jsonl...\")\nobj = search_log(log_path)\nif obj is None:\n    print(\"Checking transcript_full.jsonl...\")\n    obj = search_log(log_full_path)\n\nif obj:\n    print(\"Found commit/step with build_pcb.py!\")\n    # Let's print some of it to see\n    content = json.dumps(obj, indent=2)\n    # Write to a file\n    with open(r\"C:\\Users\\GIRTEC\\.gemini\\antigravity-cli\\brain\\a8e23cc2-b402-44c7-a956-a3b161a20562\\scratch\\extracted_log_step.json\", \"w\", encoding=\"utf-8\") as out:\n        out.write(content)\n    print(\"Wrote log step to scratch/extracted_log_step.json\")\nelse:\n    print(\"build_pcb.py content not found in log files.\")\n"